export function makeExternalStore(createObservation, name) {
  let lastResult;
  function getSnapShot() {
    return lastResult;
  }
  function subscribe(notifyUpdate) {
    const obs = createObservation({
      next: payload => {
        lastResult = payload;
        notifyUpdate();
      },
      error: error => {
        lastResult = {
          ...(lastResult ?? {}),
          error: error instanceof Error ? error : new Error(String(error))
        };
        notifyUpdate();
      },
      complete: () => {}
    });
    return () => {
      obs.unsubscribe();
    };
  }
  return {
    subscribe,
    getSnapShot
  };
}